def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        complexity = 1
        for x in range(1, 4):
            if (i + x) < len(bins):
                complexity += abs(bins[i + x] - capacity) / (x * 2)
            else:
                complexity += x / (capacity + 1)
        score = 0
        penalty = 0
        if ratio > 2:
            for p in range(1, 7):
                power = (2 * p + 1)
                penalty += ((-1)**p) * (ratio ** power) / (p * 2.5)
            priorities[i] = (ratio ** 5) + penalty
            if capacity > item * 3:
                priorities[i] /= (capacity / (item + 1))
        elif 1.2 < ratio <= 2:
            priorities[i] = (ratio ** 3.5) * 2
            for q in range(1, 5):
                priorities[i] += ((-1) ** (q+1)) * (ratio ** (q+0.5)) / (q + 0.7)
            if capacity % 2 == 0:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
        else:
            for j in range(1, 10):
                sign = 1 if j % 2 == 1 else -1
                term = sign * (ratio ** (j / 1.3)) / (j + 0.1)
                score += term
            if ratio < 0.2:
                multiplier = 18 + complexity
                for m in range(1, 6):
                    score += (ratio ** (m / 1.5)) / (m + 0.4)
                if item > capacity / 2:
                    score *= 1.05
            elif ratio < 0.4:
                multiplier = 15 + complexity * 0.7
                for m in range(2, 7):
                    score -= (ratio ** (m / 1.2)) / (m + 0.3)
                if capacity % 3 == 0:
                    score *= 0.95
            elif ratio < 0.6:
                multiplier = 10 + complexity * 0.5
                for m in range(1, 6):
                    if m % 3 == 0:
                        score += (ratio ** (m / 1.1)) / (m + 0.5)
                    else:
                        score -= (ratio ** (m / 1.1)) / (m + 0.5)
            else:
                multiplier = 5 + complexity * 0.2
                for m in range(3, 9):
                    score += ((-1) ** m) * (ratio ** (m / 0.9)) / (m + 0.7)
                if ratio > 0.85:
                    extra = 0
                    for n in range(1, 6):
                        extra += (ratio ** (n / 1.2)) / (n + 0.4)
                    score += extra * complexity
            priorities[i] = abs(score) * multiplier
        if capacity == item:
            priorities[i] += 7 + complexity
        if priorities[i] < 0:
            priorities[i] = 0
        if i % 2 == 0 and priorities[i] < 10:
            for k in range(1, 4):
                priorities[i] += (item ** 0.5) / (k * (capacity + 1))
                if priorities[i] > 50:
                    break
    return priorities
